import React from "react";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Awards({ awards, education }) {
  return (
    <>
      <style>{`
        .awards-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          background: var(--surface);
          border-top: 1px solid var(--border);
          border-bottom: 1px solid var(--border);
        }

        .awards-grid {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: clamp(1.5rem, 4vw, 3.5rem);
          align-items: start;
        }

        .awards-col {
          display: flex;
          flex-direction: column;
        }

        /* ── Unified heading size across BOTH columns ── */
        .col-heading {
          font-family: var(--font-display);
          font-weight: 800;
          font-size: clamp(1.4rem, 3vw, 2rem); /* controlled — won't wrap */
          color: var(--text);
          margin-bottom: 1.25rem;
          line-height: 1.15;
          white-space: nowrap;        /* prevent wrapping on desktop */
        }

        /* ── Award cards ── */
        .award-card {
          background: var(--surface2);
          border: 1px solid rgba(245,158,11,0.18);
          border-radius: var(--radius);
          padding: clamp(1rem, 2.5vw, 1.5rem);
          margin-bottom: 0.85rem;
          transition: border-color 0.2s;
        }
        .award-card:last-child { margin-bottom: 0; }
        .award-card:hover { border-color: var(--accent3); }

        .award-inner { display: flex; gap: 10px; align-items: flex-start; }
        .award-icon { font-size: clamp(1.1rem, 2.5vw, 1.4rem); flex-shrink: 0; }

        .award-title {
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.82rem, 1.3vw, 0.95rem);
          color: var(--accent3);
          margin-bottom: 5px;
          line-height: 1.3;
        }
        .award-desc {
          font-size: clamp(0.75rem, 1.1vw, 0.855rem);
          color: var(--muted);
          line-height: 1.6;
        }

        /* ── Education cards ── */
        .edu-card {
          background: var(--surface2);
          border: 1px solid rgba(124,58,237,0.18);
          border-radius: var(--radius);
          padding: clamp(1rem, 2.5vw, 1.5rem);
          margin-bottom: 0.85rem;
          transition: border-color 0.2s;
        }
        .edu-card:last-child { margin-bottom: 0; }
        .edu-card:hover { border-color: var(--accent2); }

        .edu-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          gap: 0.5rem;
          margin-bottom: 5px;
          flex-wrap: wrap;
        }
        .edu-degree {
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.8rem, 1.3vw, 0.95rem);
          color: var(--accent2);
          line-height: 1.3;
          flex: 1;
          min-width: 0;
          word-break: break-word;
        }
        .edu-yr {
          font-size: clamp(0.65rem, 0.95vw, 0.75rem);
          color: var(--muted);
          background: rgba(124,58,237,0.1);
          border: 1px solid rgba(124,58,237,0.2);
          border-radius: 99px;
          padding: 2px 10px;
          white-space: nowrap;
          flex-shrink: 0;
        }
        .edu-inst {
          font-size: clamp(0.72rem, 1.1vw, 0.82rem);
          color: var(--muted);
          line-height: 1.5;
        }

        /* ── Responsive breakpoints ── */

        /* Large desktop / TV (1400px+) */
        @media (min-width: 1400px) {
          .col-heading { font-size: 2.1rem; white-space: nowrap; }
          .award-title, .edu-degree { font-size: 1rem; }
          .award-desc, .edu-inst { font-size: 0.9rem; }
        }

        /* Tablet landscape (900–1199px) */
        @media (max-width: 1199px) {
          .col-heading { font-size: clamp(1.2rem, 2.5vw, 1.6rem); white-space: normal; }
        }

        /* Tablet portrait (701–900px) */
        @media (max-width: 900px) {
          .awards-grid { gap: 1.25rem; }
          .col-heading { font-size: clamp(1.1rem, 3vw, 1.4rem); }
        }

        /* Mobile (≤700px) — single column */
        @media (max-width: 700px) {
          .awards-grid { grid-template-columns: 1fr; }
          .col-heading { font-size: clamp(1.4rem, 6vw, 1.8rem); white-space: normal; }
          .award-title, .edu-degree { font-size: 0.9rem; }
          .award-desc, .edu-inst { font-size: 0.8rem; }
        }

        /* Small mobile (≤400px) */
        @media (max-width: 400px) {
          .awards-section { padding: 2rem 1rem; }
          .col-heading { font-size: 1.3rem; }
        }
      `}</style>

      <section className="awards-section" id="awards">
        <div className="awards-grid">

          {/* ── Left: Awards ── */}
          <div className="awards-col">
            <SectionLabel text="Recognition" />
            <h2 className="col-heading">Honors &amp; Awards</h2>
            {awards.map((a, i) => (
              <div key={i} className="award-card">
                <div className="award-inner">
                  <span className="award-icon">🏆</span>
                  <div>
                    <div className="award-title">{a.title}</div>
                    <div className="award-desc">{a.description}</div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* ── Right: Education ── */}
          <div className="awards-col">
            <SectionLabel text="Education" />
            <h2 className="col-heading">Academic Background</h2>
            {education.map((e, i) => (
              <div key={i} className="edu-card">
                <div className="edu-header">
                  <div className="edu-degree">{e.degree}</div>
                  <span className="edu-yr">{e.year}</span>
                </div>
                <div className="edu-inst">{e.institution}</div>
              </div>
            ))}
          </div>

        </div>
      </section>
    </>
  );
}
